import java.io.*;
import java.util.*;

public class Main {
    static final long MOD = 1_000_000_007L;
    static long[] fact;
    static long[] invFact;
    static long modPow(long a, long e) {
        long res = 1L;
        a %= MOD;
        while (e > 0) {
            if ((e & 1) == 1) res = (res * a) % MOD;
            a = (a * a) % MOD;
            e >>= 1;
        }
        return res;
    }
    static long nCr(int n, int r) {
        if (r < 0 || r > n) return 0L;
        return (((fact[n] * invFact[r]) % MOD) * invFact[n - r]) % MOD;
    }
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st;
        int T = Integer.parseInt(br.readLine().trim());
        int maxN = 5000; // as per constraints
        fact = new long[maxN + 1];
        invFact = new long[maxN + 1];
        fact[0] = 1;
        for (int i = 1; i <= maxN; i++) fact[i] = (fact[i - 1] * i) % MOD;
        invFact[maxN] = modPow(fact[maxN], MOD - 2);
        for (int i = maxN; i > 0; i--) invFact[i - 1] = (invFact[i] * i) % MOD;
        StringBuilder sb = new StringBuilder();
        for (int tc = 0; tc < T; tc++) {
            st = new StringTokenizer(br.readLine());
            int N = Integer.parseInt(st.nextToken());
            int K = Integer.parseInt(st.nextToken());
            long ans = 0L;
            int runs = K + 1;
            // start with Right
            int rRuns = (runs + 1) / 2; // ceil
            int dRuns = runs / 2;       // floor
            if (rRuns <= N - 1 && dRuns <= N - 1) {
                long waysR = nCr(N - 2, rRuns - 1);
                long waysD = nCr(N - 2, dRuns - 1);
                ans = (ans + waysR * waysD) % MOD;
            }
            // start with Down
            dRuns = (runs + 1) / 2;
            rRuns = runs / 2;
            if (rRuns <= N - 1 && dRuns <= N - 1) {
                long waysR = nCr(N - 2, rRuns - 1);
                long waysD = nCr(N - 2, dRuns - 1);
                ans = (ans + waysR * waysD) % MOD;
            }
            sb.append(ans).append('\n');
        }
        System.out.print(sb.toString());
    }
}

